// Build context for Agent 0 and Agent 1
const redditData = $('📡 Fetch Reddit Trending').item.json;
const sheetsData = $('📡 Load Existing Topics').item.json;

// Extract reddit titles and scores
const posts = redditData?.data?.children || [];
const trendingTopics = posts
  .filter(p => p?.data?.score > 10)
  .slice(0, 10)
  .map(p => `- "${p.data.title}" (upvotes: ${p.data.score}, subreddit: r/${p.data.subreddit})`)
  .join('\n');

// Extract existing keywords from content log
const rows = Array.isArray(sheetsData) ? sheetsData.slice(1) : [];
const existingKeywords = rows
  .map(r => r['Keyword'] || r[2] || '')
  .filter(Boolean)
  .slice(0, 50)
  .join(', ');

return [{ json: {
  reddit_context: trendingTopics || 'No trending data available - use your research',
  existing_keywords: existingKeywords || 'None yet',
  today: new Date().toLocaleDateString('en-MY', { timeZone: 'Asia/Kuala_Lumpur' }),
  total_existing: rows.length
}}];

const now = new Date();
const formatted = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const user_message = `You are a master prompt engineer for a content automation system.
Today is ${formatted}. Niche: practical how-to guides.

Generate a JSON prompt package for today's content pipeline:
{
  "research_context": "Instructions for finding 3 trending how-to topics with high search intent and affiliate potential. Prioritize topics with: clear actionable steps, product recommendations possible, large audience.",
  "writer_instructions": "Instructions for writing a 2800+ word expert how-to article. Must include: compelling H1, intro with problem hook, 7-9 H2 sections with numbered steps, expert tips callouts, FAQ section (5 questions), conclusion with CTA. Tone: conversational expert.",
  "humanizer_instructions": "Instructions for rewriting to sound like a genuine expert blogger sharing personal experience. Add first-person observations, vary sentence rhythm, remove generic phrases, keep all factual content.",
  "seo_instructions": "Instructions for SEO optimization. Must produce: meta_title (under 60 chars), meta_description (under 155 chars), focus_keyword, tags array (8-10), affiliate disclosure at article top, 3 naturally integrated affiliate CTAs.",
  "qc_rubric": "Scoring rubric: word_count (min 2800, max 5000), readability (plain English), seo_compliance, affiliate_disclosure_present, factual_accuracy, reader_value. Score each 1-10. Approved if all scores >= 6 and avg >= 7.",
  "social_instructions": "Instructions for creating platform posts from the article. Facebook: engaging caption with emoji. Instagram: caption + CTA + 10 relevant hashtags. Pinterest: pin title + 200 char description + board name. YouTube Short script: 60 sec, hook/problem/solution/CTA. Save TikTok as script only."
}

Return only valid JSON, no markdown.`;
return [{ json: { user_message, system_message: '', model: 'llama3.2:latest', temperature: 0.4, num_predict: 4096 } }];

const raw = $input.first().json.message?.content || $input.first().json.response || '';
let pkg;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  pkg = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  // Fallback prompt package
  pkg = {
    research_context: "Find the single best trending how-to topic today with high search intent and affiliate potential. Return as JSON with: topic, primary_keyword, secondary_keywords, affiliate_angle, content_outline (7-9 H2 sections).",
    writer_instructions: "Write a comprehensive 2800+ word how-to article in HTML format. Include compelling H1, intro with problem hook, 7-9 H2 sections with steps, expert tips, FAQ (5 questions), conclusion with CTA.",
    humanizer_instructions: "Rewrite this article to sound like a genuine expert blogger. Add personal voice, vary sentences, remove corporate language. Keep all HTML and facts.",
    seo_instructions: "Optimize for SEO. Add affiliate disclosure at top, meta title (60 chars), meta description (155 chars), focus keyword, tags (10), and 3 affiliate CTAs naturally integrated.",
    qc_rubric: "Score 1-10 on: word_count (min 2800), readability, seo_compliance, affiliate_disclosure_present, reader_value. Approve if all >= 6.",
    social_instructions: "Create: Facebook caption, Instagram caption + 10 hashtags, Pinterest pin title + description, YouTube Short script (60 sec), TikTok script (60 sec).",
    parse_error: e.message
  };
}
return [{ json: pkg }];

const pkg = $('📋 Parse Prompt Package').item.json;
const ctx = $('🔧 Build Research Context').item.json;
const user_message = `${pkg.research_context}

REAL TRENDING DATA FROM REDDIT (use this to select topics):
${ctx.reddit_context}

EXISTING PUBLISHED TOPICS (DO NOT REPEAT THESE):
${ctx.existing_keywords}

Select the SINGLE best topic to write about today. Return JSON:
{
  "topic": "exact article title",
  "primary_keyword": "main SEO keyword",
  "secondary_keywords": ["kw1", "kw2", "kw3"],
  "search_intent": "informational|transactional|navigational",
  "affiliate_angle": "which products could be recommended",
  "content_outline": ["H2 section 1", "H2 section 2", "...7-9 total"],
  "word_count_target": 3000,
  "is_halal_compliant": true,
  "not_duplicate": true
}

Return only valid JSON.`;
return [{ json: { user_message, system_message: '', model: 'llama3.2:latest', temperature: 0.7, num_predict: 4096 } }];

const raw = $input.first().json.message?.content || $input.first().json.response || '';
let topic;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  topic = JSON.parse(match ? (match[1] || match[0]) : raw);
  if (!topic.topic || !topic.primary_keyword) throw new Error('Missing fields');
  topic.generated_at = new Date().toISOString();
  topic.word_count_target = topic.word_count_target || 3000;
} catch(e) {
  topic = {
    topic: "How to Build a Profitable Online Business in 2025",
    primary_keyword: "build online business",
    secondary_keywords: ["make money online", "online business ideas"],
    affiliate_angle: "business tools and courses",
    content_outline: ["Why Start an Online Business Now","Choosing Your Business Model","Setting Up Your Foundation","Finding Your First Customers","Scaling with Automation","Common Mistakes to Avoid","Your 30-Day Action Plan"],
    word_count_target: 3000,
    is_halal_compliant: true,
    not_duplicate: true,
    generated_at: new Date().toISOString(),
    status: "fallback_topic",
    error: e.message
  };
}
return [{ json: topic }];

const pkg = $('📋 Parse Prompt Package').item.json;
const topic = $('✅ Parse & Validate Topic').item.json;
const outline = Array.isArray(topic.content_outline) ? topic.content_outline.join(', ') : topic.content_outline;
const user_message = `${pkg.writer_instructions}

TOPIC: ${topic.topic}
PRIMARY KEYWORD: ${topic.primary_keyword}
CONTENT OUTLINE: ${outline}
TARGET WORDS: ${topic.word_count_target || 3000}

Write the complete article now. Use HTML formatting (h1, h2, h3, p, ul, ol, strong).
Return the full article HTML. No JSON wrapper, just the raw HTML article.`;
return [{ json: { user_message, system_message: '', model: 'llama3.2:latest', temperature: 0.8, num_predict: 4000 } }];

const pkg = $('📋 Parse Prompt Package').item.json;
const article = $('✍️ Agent 2: Content Writer').item.json.message?.content || '';
const user_message = `${pkg.humanizer_instructions}

ARTICLE TO HUMANIZE:
${article}

Rewrite the entire article. Keep all HTML tags, structure, and factual content intact.
Return only the rewritten HTML article.`;
return [{ json: { user_message, system_message: '', model: 'llama3.2:latest', temperature: 0.9, num_predict: 4000 } }];

const pkg = $('📋 Parse Prompt Package').item.json;
const humanized = $('🧂 Agent 3: Humanizer').item.json.message?.content || '';
const topic = $('✅ Parse & Validate Topic').item.json;
const user_message = `${pkg.seo_instructions}

ARTICLE:
${humanized}

TOPIC: ${topic.topic}
PRIMARY KEYWORD: ${topic.primary_keyword}
AFFILIATE ANGLE: ${topic.affiliate_angle || ''}

IMPORTANT: You MUST add this exact disclosure at the very top of the article content, before the first paragraph:
<p><em><strong>Disclosure:</strong> This article contains affiliate links. If you purchase through our links, we may earn a commission at no extra cost to you. We only recommend products we genuinely believe in.</em></p>

Return JSON:
{
  "optimized_content": "full HTML article with disclosure at top and affiliate CTAs integrated",
  "meta_title": "SEO title under 60 chars",
  "meta_description": "compelling description under 155 chars",
  "focus_keyword": "primary keyword",
  "slug": "url-friendly-slug",
  "tags": ["tag1","tag2","...up to 10"],
  "categories": ["Main Category"],
  "affiliate_ctas_added": 3
}`;
return [{ json: { user_message, system_message: '', model: 'llama3.2:latest', temperature: 0.4, num_predict: 4000 } }];

const raw = $('🎯 Agent 4: SEO & Monetization').item.json.message?.content || '';
let seo;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/s);
  seo = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  // Fallback: use humanized content directly
  seo = {
    optimized_content: $('🧂 Agent 3: Humanizer').item.json.message?.content || '',
    meta_title: $('✅ Parse & Validate Topic').item.json.topic,
    meta_description: 'A comprehensive how-to guide. Read the full article for step-by-step instructions.',
    focus_keyword: $('✅ Parse & Validate Topic').item.json.primary_keyword,
    slug: $('✅ Parse & Validate Topic').item.json.primary_keyword?.replace(/\s+/g, '-').toLowerCase(),
    tags: $('✅ Parse & Validate Topic').item.json.secondary_keywords || [],
    categories: ['How-To'],
    affiliate_ctas_added: 0,
    parse_error: e.message
  };
}

const content = seo.optimized_content || '';
const wordCount = content.replace(/<[^>]*>/g,' ').split(/\s+/).filter(Boolean).length;
const excerpt = content.replace(/<[^>]*>/g,' ').substring(0, 200).trim() + '...';

return [{ json: {
  title: seo.meta_title || $('✅ Parse & Validate Topic').item.json.topic,
  content,
  word_count: wordCount,
  excerpt,
  slug: seo.slug || seo.meta_title?.replace(/\s+/g,'-').toLowerCase(),
  focus_keyword: seo.focus_keyword,
  meta_description: seo.meta_description,
  tags: seo.tags || [],
  categories: seo.categories || ['How-To'],
  affiliate_ctas: seo.affiliate_ctas_added || 0,
  assembled_at: new Date().toISOString()
}}];

const pkg = $('📋 Parse Prompt Package').item.json;
const assembled = $('🔧 Assemble Final Article').item.json;
const contentExcerpt = (assembled.content || '').substring(0, 3000) + '...';
const user_message = `${pkg.qc_rubric}

ARTICLE TO REVIEW:
${contentExcerpt}

METADATA:
- Title: ${assembled.title}
- Word Count: ${assembled.word_count}
- Focus Keyword: ${assembled.focus_keyword}

Return JSON:
{
  "approved": true,
  "scores": {
    "word_count": 8,
    "readability": 7,
    "seo_compliance": 8,
    "affiliate_disclosure": 10,
    "factual_accuracy": 8,
    "reader_value": 9
  },
  "average_score": 8.3,
  "rejection_reason": null,
  "suggestions": ["optional improvement notes"]
}`;
return [{ json: { user_message, system_message: '', model: 'llama3.2:latest', temperature: 0.3, num_predict: 4096 } }];

const raw = $input.first().json.message?.content || '';
let qcResult;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  qcResult = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  qcResult = { approved: false, error: e.message };
}
return [{ json: qcResult }];

const topic = $('✅ Parse & Validate Topic').item.json;
const keyword = topic.primary_keyword || topic.topic || 'productivity';
const queries = [
  keyword,
  keyword.split(' ').slice(0,2).join(' '),
  topic.secondary_keywords?.[0] || 'business success'
];
return [{ json: { queries, primary_query: queries[0] }}];

const items = $input.all();
const input1 = items[0]?.json || {};
const input2 = items[1]?.json || {};
let imageUrl = null;
let imageAlt = $('✅ Parse & Validate Topic').item.json.primary_keyword || 'article image';

// Try Pexels first (input1)
try {
  if (input1.photos && input1.photos.length > 0) {
    imageUrl = input1.photos[0].src?.large || input1.photos[0].src?.original;
  }
} catch(e) {}

// Fallback to Pixabay (input2)
if (!imageUrl) {
  try {
    if (input2.hits && input2.hits.length > 0) {
      imageUrl = input2.hits[0].largeImageURL || input2.hits[0].webformatURL;
    }
  } catch(e) {}
}

const needsAI = !imageUrl;
return [{ json: { image_url: imageUrl, image_alt: imageAlt, needs_ai_image: needsAI }}];

const mediaResponse = $input.first().json;
const mediaId = mediaResponse.id || null;
const mediaUrl = mediaResponse.source_url || mediaResponse.guid?.rendered || '';
const imageAlt = $('🔀 Select Best Image').item.json.image_alt || '';

return [{ json: { media_id: mediaId, media_url: mediaUrl, image_alt: imageAlt }}];

const pkg = $('📋 Parse Prompt Package').item.json;
const assembled = $('🔧 Assemble Final Article').item.json;
const wpLink = $('📄 Publish to WordPress').item.json.link || '';
const user_message = `${pkg.social_instructions}

ARTICLE TITLE: ${assembled.title}
ARTICLE URL: ${wpLink}
EXCERPT: ${assembled.excerpt}
PRIMARY KEYWORD: ${assembled.focus_keyword}

Return JSON:
{
  "facebook": { "caption": "engaging post with emoji and question to drive comments", "link": "${wpLink}" },
  "instagram": { "caption": "value-packed caption with CTA", "hashtags": ["#tag1","#tag2","...10 tags"] },
  "pinterest": { "title": "pin title under 100 chars", "description": "keyword-rich 200 char description", "board": "suggested board name" },
  "youtube_script": "full 60-second script with timestamps: [0-3s] HOOK [3-15s] PROBLEM [15-45s] STEPS [45-60s] CTA",
  "tiktok_script": "same 60-second script adapted for TikTok tone",
  "reel_script": "scene-by-scene: HOOK text | PROBLEM | SOLUTION STEPS | CTA link-in-bio"
}`;
return [{ json: { user_message, system_message: '', model: 'llama3.2:latest', temperature: 0.9, num_predict: 4096 } }];

const raw = $input.first().json.message?.content || '';
let posts;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/s);
  posts = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  posts = { parse_error: e.message, raw: raw.substring(0,300) };
}

const blogUrl = $('📄 Publish to WordPress').item.json.link || 'https://your-blog.com';
const title = $('🔧 Assemble Final Article').item.json.title;

return [
  { json: { platform: 'facebook', caption: posts.facebook?.caption || title, link: blogUrl, data: posts.facebook }},
  { json: { platform: 'instagram', caption: (posts.instagram?.caption || title) + '\n\n' + (posts.instagram?.hashtags?.join(' ') || ''), link: blogUrl, data: posts.instagram }},
  { json: { platform: 'pinterest', title: posts.pinterest?.title || title, description: posts.pinterest?.description || '', link: blogUrl, board: posts.pinterest?.board || 'How-To Guides', data: posts.pinterest }},
  { json: { platform: 'youtube_short', script: posts.youtube_script || '', blog_url: blogUrl, article_title: title }},
  { json: { platform: 'tiktok', script: posts.tiktok_script || '', blog_url: blogUrl, article_title: title }},
  { json: { platform: 'reel', script: posts.reel_script || '', blog_url: blogUrl, article_title: title }}
];

const item = $input.first().json;
const postTopic = item.post_topic || item.post?.title || 'how-to guide';
const commentContent = item.comment_content || item.content?.rendered?.replace(/<[^>]*>/g,'') || '';
const authorName = item.author_name || item.author?.name || 'Reader';
const user_message = `You are a helpful blog comment moderator. Review this comment and respond appropriately.

BLOG TOPIC: ${postTopic}
COMMENT: ${commentContent}
COMMENTER: ${authorName}

Classify and respond:
{
  "classification": "genuine_question|praise|negative|spam|gibberish|self_promotion",
  "action": "approve_and_reply|mark_spam|trash",
  "reply": "your friendly helpful reply here (null if spam/trash)",
  "tone": "helpful|warm|empathetic"
}

Be genuine, helpful, and human. Keep replies under 100 words.`;
return [{ json: { ...item, user_message, system_message: '', model: 'llama3.2:latest', temperature: 0.7, num_predict: 2048 } }];

const raw = $input.first().json.message?.content || '';
let decision;
try {
  const match = raw.match(/```json\n([\s\S]*?)\n```/) || raw.match(/(\{[\s\S]*\})/);
  decision = JSON.parse(match ? (match[1] || match[0]) : raw);
} catch(e) {
  decision = { classification: 'genuine_question', action: 'approve_and_reply', reply: null };
}

const comments = Array.isArray($('💬 Fetch Pending Comments').item.json) 
  ? $('💬 Fetch Pending Comments').item.json : [];

const toReply = comments.filter(c => c.status === 'hold').map(c => ({
  comment_id: c.id,
  post_id: c.post,
  author: c.author_name,
  content: c.content?.rendered?.replace(/<[^>]*>/g,'') || '',
  action: decision.action,
  reply: decision.reply,
  classification: decision.classification
}));

return toReply.length > 0 ? toReply.map(c => ({ json: c })) : [{ json: { no_comments: true }}];
